 1	import * as React from 'react';
 2	import { useODFSystemFlagsSelector } from '@odf/core/redux';
 3	import { PrometheusUtilizationItem } from '@odf/shared/dashboards/utilization-card/prometheus-utilization-item';
 4	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
 5	import { humanizeDecimalBytesPerSec } from '@odf/shared/utils';
 6	import { UtilizationDurationDropdown } from '@openshift-console/dynamic-plugin-sdk-internal';
 7	import { Grid, Card, CardHeader, CardTitle } from '@patternfly/react-core';
 8	import { getPoolQuery, StorageDashboardQuery } from '../../queries';
 9	import { humanizeIOPS } from '../persistent-internal/utilization-card/utils';
10	import { BlockPoolDashboardContext } from './block-pool-dashboard-context';
11	
12	export const UtilizationCard: React.FC = () => {
13	  const { t } = useCustomTranslation();
14	  const { obj } = React.useContext(BlockPoolDashboardContext);
15	  const { name, namespace: clusterNs } = obj.metadata;
16	
17	  const { systemFlags } = useODFSystemFlagsSelector();
18	  const managedByOCS = systemFlags[clusterNs]?.ocsClusterName;
19	
20	  return (
21	    <Card>
22	      <CardHeader
23	        actions={{
24	          actions: <UtilizationDurationDropdown />,
25	          hasNoOffset: false,
26	          className: undefined,
27	        }}
28	      >
29	        <CardTitle>{t('Performance')}</CardTitle>
30	      </CardHeader>
31	      <Grid className="odf-block-pool-utilization-card-body pf-v6-u-ml-lg pf-v6-u-mr-md">
32	        <PrometheusUtilizationItem
33	          title={t('IOPS')}
34	          utilizationQuery={getPoolQuery(
35	            [name],
36	            StorageDashboardQuery.POOL_UTILIZATION_IOPS_QUERY,
37	            managedByOCS
38	          )}
39	          humanizeValue={humanizeIOPS(t)}
40	        />
41	        <PrometheusUtilizationItem
42	          title={t('Throughput')}
43	          utilizationQuery={getPoolQuery(
44	            [name],
45	            StorageDashboardQuery.POOL_UTILIZATION_THROUGHPUT_QUERY,
46	            managedByOCS
47	          )}
48	          humanizeValue={humanizeDecimalBytesPerSec}
49	        />
50	      </Grid>
51	    </Card>
52	  );
53	};
54	
55	export default UtilizationCard;

